/// ```dart
/// filter((a) => a % 2 == 0, [0, 1, 2, 3, 4, 5, 6]); // (0, 2, 4, 6)
/// ```
Iterable<A> filter<A>(bool Function(A a) f, Iterable<A> iterable) sync* {
  for (final a in iterable) {
    if (f(a)) yield a;
