      }).catchError((Object reason, StackTrace st) {
        finished = true;
        while (settlementQueue.isNotEmpty) {
          settlementQueue.removeAt(0).completeError(reason, st);
        }
      });
    }

    void consumeBuffer() {
      while (buffer.isNotEmpty && nextCallCount > resolvedCount) {
        final value = buffer.removeAt(0);
        settlementQueue.removeAt(0).complete(IterResult.value(value));
        resolvedCount++;
      }
    }

    recur = (Concurrent? concurrent) {
      if (finished || nextCallCount == resolvedCount) {
        return;
      } else if (buffer.isNotEmpty) {
        consumeBuffer();
      } else {
        fillBuffer(concurrent);
      }
    };

    return DelegateAsyncIterator((concurrent) {
      nextCallCount++;
      if (finished) {
        return Future.value(IterResult<A>.done());
      }
      final completer = Completer<IterResult<A>>();
      settlementQueue.add(completer);
      recur(concurrent);
      return completer.future;
    });
  });
}

/// Async counterpart of [filter]. The predicate may return a [Future].
///
/// Port of FxTS `filter` (async), including its dedicated concurrent path.
FxAsyncIterable<A> filterAsync<A>(
    FutureOr<bool> Function(A a) f, FxAsyncIterable<A> iterable) {
  return DelegateAsyncIterable(() {
    FxAsyncIterator<A>? inner;
    return DelegateAsyncIterator((concurrent) {
      if (inner == null) {
        if (concurrent is Concurrent) {
          inner = _asyncConcurrent(concurrentAsync(
                  concurrent.length, _toFilterIterable(f, iterable)))
              .iterator;
        } else {
          final iterator = iterable.iterator;
          inner = SerialAsyncIterator((c) async {
            while (true) {
              final result = await iterator.next(c);
              if (result.done) return IterResult<A>.done();
              if (await f(result.value)) {
                return IterResult.value(result.value);
              }
            }
          });
        }
      }
      return inner!.next(concurrent);
    });
  });
}

/// Async counterpart of [reject].
FxAsyncIterable<A> rejectAsync<A>(
        FutureOr<bool> Function(A a) f, FxAsyncIterable<A> iterable) =>
    filterAsync((A a) async => !await f(a), iterable);

/// Async counterpart of [compact].
FxAsyncIterable<A> compactAsync<A>(FxAsyncIterable<A?> iterable) =>
    mapAsync((A? a) => a as A, filterAsync((A? a) => a != null, iterable));

// --- uniq / set operations ----------------------------------------------

/// Returns an iterable with unique values as determined by [f].
///
/// Port of FxTS `uniqBy`.
Iterable<A> uniqBy<A, B>(B Function(A a) f, Iterable<A> iterable) sync* {
  final seen = <B>{};
  for (final a in iterable) {
    if (seen.add(f(a))) yield a;
  }
}

/// Returns an iterable with duplicate values removed.
///
/// Port of FxTS `uniq`.
Iterable<A> uniq<A>(Iterable<A> iterable) => uniqBy((A a) => a, iterable);

/// Async counterpart of [uniqBy].
FxAsyncIterable<A> uniqByAsync<A, B>(
    FutureOr<B> Function(A a) f, FxAsyncIterable<A> iterable) {
  return DelegateAsyncIterable(() {
    final seen = <B>{};
    return filterAsync((A a) async => seen.add(await f(a)), iterable).iterator;
  });
}

/// Async counterpart of [uniq].
FxAsyncIterable<A> uniqAsync<A>(FxAsyncIterable<A> iterable) =>
    uniqByAsync((A a) => a, iterable);

/// Returns the elements of [iterable2] whose [f]-keys do not occur in
/// [iterable1], with duplicates removed.
///
/// Port of FxTS `differenceBy`.
Iterable<A> differenceBy<A, B>(
    B Function(A a) f, Iterable<A> iterable1, Iterable<A> iterable2) sync* {
  final set = map(f, iterable1).toSet();
  yield* uniq(reject((A a) => set.contains(f(a)), iterable2));
}

/// Returns the elements of [iterable2] that do not occur in [iterable1].
///
/// Port of FxTS `difference`.
Iterable<A> difference<A>(Iterable<A> iterable1, Iterable<A> iterable2) =>
    differenceBy((A a) => a, iterable1, iterable2);

/// Returns the elements of [iterable2] whose [f]-keys also occur in
/// [iterable1], with duplicates removed.
///
/// Port of FxTS `intersectionBy`.
Iterable<A> intersectionBy<A, B>(
    B Function(A a) f, Iterable<A> iterable1, Iterable<A> iterable2) sync* {
  final set = map(f, iterable1).toSet();
  yield* uniq(filter((A a) => set.contains(f(a)), iterable2));
}

/// Returns the elements of [iterable2] that also occur in [iterable1].
///
/// Port of FxTS `intersection`.
Iterable<A> intersection<A>(Iterable<A> iterable1, Iterable<A> iterable2) =>
    intersectionBy((A a) => a, iterable1, iterable2);

FxAsyncIterable<A> _setOpAsync<A, B>(
  FutureOr<B> Function(A a) f,
  FxAsyncIterable<A> iterable1,
  FxAsyncIterable<A> iterable2,
  bool keepWhenInSet,
) {
  // The concurrency marker applies to iterable2, as in FxTS.
  return dispatchAsync(iterable2, (source) {
    Set<B>? set;
    FxAsyncIterator<A>? inner;
    return SerialAsyncIterator((concurrent) async {
      if (set == null) {
        final keys = <B>[];
        final it1 = iterable1.iterator;
        while (true) {
          final r = await it1.next();
          if (r.done) break;
          keys.add(await f(r.value));
        }
        set = keys.toSet();
        inner = uniqAsync(filterAsync(
                (A a) async => set!.contains(await f(a)) == keepWhenInSet,
                source))
            .iterator;
      }
      return inner!.next(concurrent);
    });
  });
}

/// Async counterpart of [differenceBy].
FxAsyncIterable<A> differenceByAsync<A, B>(FutureOr<B> Function(A a) f,
        FxAsyncIterable<A> iterable1, FxAsyncIterable<A> iterable2) =>
    _setOpAsync(f, iterable1, iterable2, false);

/// Async counterpart of [difference].
FxAsyncIterable<A> differenceAsync<A>(
        FxAsyncIterable<A> iterable1, FxAsyncIterable<A> iterable2) =>
    differenceByAsync((A a) => a, iterable1, iterable2);

/// Async counterpart of [intersectionBy].
FxAsyncIterable<A> intersectionByAsync<A, B>(FutureOr<B> Function(A a) f,
        FxAsyncIterable<A> iterable1, FxAsyncIterable<A> iterable2) =>
    _setOpAsync(f, iterable1, iterable2, true);

/// Async counterpart of [intersection].
FxAsyncIterable<A> intersectionAsync<A>(
        FxAsyncIterable<A> iterable1, FxAsyncIterable<A> iterable2) =>
    intersectionByAsync((A a) => a, iterable1, iterable2);

// ---- lib/src/lazy/take_drop.dart ----


/// Returns an iterable of the first [length] values from [iterable].
///
/// Port of FxTS `take`.
Iterable<A> take<A>(int length, Iterable<A> iterable) sync* {
  if (length < 1) return;
  var remaining = length;
  for (final a in iterable) {
    yield a;
    if (--remaining < 1) return;
  }
}

/// Async counterpart of [take]. Pass-through: overlapping pulls stay
/// parallel, as in FxTS.
FxAsyncIterable<A> takeAsync<A>(int length, FxAsyncIterable<A> iterable) {
  return DelegateAsyncIterable(() {
    final iterator = iterable.iterator;
    var remaining = length;
    return DelegateAsyncIterator((concurrent) {
      if (remaining-- < 1) return Future.value(IterResult<A>.done());
      return iterator.next(concurrent);
    });
  });
}

/// Returns an iterable of the last [length] values.
///
/// Port of FxTS `takeRight` (materializes the source).
Iterable<A> takeRight<A>(int length, Iterable<A> iterable) sync* {
  if (length < 0) throw RangeError("'length' must be greater than 0");
  final arr = iterable.toList(growable: false);
  for (var i = arr.length - length < 0 ? 0 : arr.length - length;
      i < arr.length;
      i++) {
    yield arr[i];
  }
}

/// Async counterpart of [takeRight].
FxAsyncIterable<A> takeRightAsync<A>(int length, FxAsyncIterable<A> iterable) {
  if (length < 0) throw RangeError("'length' must be greater than 0");
  return dispatchAsync(iterable, (source) {
    final iterator = source.iterator;
    Iterator<A>? tail;
    return SerialAsyncIterator((concurrent) async {
      if (tail == null) {
        final arr = <A>[];
        while (true) {
          final r = await iterator.next(concurrent);
          if (r.done) break;
          arr.add(r.value);
        }
        tail = takeRight(length, arr).iterator;
      }
      if (tail!.moveNext()) return IterResult.value(tail!.current);
      return IterResult<A>.done();
    });
  });
}

/// Returns an iterable that yields values as long as [f] returns true.
///
/// Port of FxTS `takeWhile`.
Iterable<A> takeWhile<A>(bool Function(A a) f, Iterable<A> iterable) sync* {
  for (final a in iterable) {
    if (!f(a)) return;
    yield a;
  }
}

/// Async counterpart of [takeWhile].
FxAsyncIterable<A> takeWhileAsync<A>(
    FutureOr<bool> Function(A a) f, FxAsyncIterable<A> iterable) {
  return dispatchAsync(iterable, (source) {
    final iterator = source.iterator;
    var end = false;
    return SerialAsyncIterator((concurrent) async {
      final result = await iterator.next(concurrent);
      if (result.done || end) return IterResult<A>.done();
      if (!await f(result.value)) {
        end = true;
        return IterResult<A>.done();
      }
      return result;
    });
  });
}

/// Returns an iterable that yields values until [f] returns true —
/// **including** the element that matched.
///
/// Port of FxTS `takeUntilInclusive`.
Iterable<A> takeUntilInclusive<A>(
    bool Function(A a) f, Iterable<A> iterable) sync* {
  for (final a in iterable) {
    yield a;
    if (f(a)) return;
  }
}

/// Async counterpart of [takeUntilInclusive].
FxAsyncIterable<A> takeUntilInclusiveAsync<A>(
    FutureOr<bool> Function(A a) f, FxAsyncIterable<A> iterable) {
  return dispatchAsync(iterable, (source) {
    final iterator = source.iterator;
    var end = false;
    return SerialAsyncIterator((concurrent) async {
      if (end) return IterResult<A>.done();
      final result = await iterator.next(concurrent);
      if (result.done || end) return IterResult<A>.done();
      if (await f(result.value)) {
        end = true;
      }
      return result;
    });
  });
}

/// Alias of [takeUntilInclusive].
///
/// Deprecated in FxTS in favor of `takeUntilInclusive`; kept for parity.
@Deprecated('Use takeUntilInclusive instead')
Iterable<A> takeUntil<A>(bool Function(A a) f, Iterable<A> iterable) =>
    takeUntilInclusive(f, iterable);

/// Alias of [takeUntilInclusiveAsync].
@Deprecated('Use takeUntilInclusiveAsync instead')
FxAsyncIterable<A> takeUntilAsync<A>(
        FutureOr<bool> Function(A a) f, FxAsyncIterable<A> iterable) =>
    takeUntilInclusiveAsync(f, iterable);

/// Returns an iterable that skips the first [length] values.
///
/// Port of FxTS `drop`.
Iterable<A> drop<A>(int length, Iterable<A> iterable) sync* {
  var remaining = length;
  for (final a in iterable) {
    if (remaining > 0) {
      remaining--;
      continue;
    }
    yield a;
  }
}

/// Async counterpart of [drop].
FxAsyncIterable<A> dropAsync<A>(int length, FxAsyncIterable<A> iterable) {
  return dispatchAsync(iterable, (source) {
    final iterator = source.iterator;
    var remaining = length;
    return SerialAsyncIterator((concurrent) async {
      while (remaining > 0) {
        remaining--;
        final r = await iterator.next(concurrent);
        if (r.done) return IterResult<A>.done();
      }
      return iterator.next(concurrent);
    });
  });
}

/// Returns an iterable that omits the last [length] values.
///
/// Port of FxTS `dropRight` (materializes the source).
Iterable<A> dropRight<A>(int length, Iterable<A> iterable) sync* {
  if (length < 0) throw RangeError("'length' must be greater than 0");
  final arr = iterable.toList(growable: false);
  for (var i = 0; i < arr.length - length; i++) {
    yield arr[i];
  }
}

/// Async counterpart of [dropRight].
FxAsyncIterable<A> dropRightAsync<A>(int length, FxAsyncIterable<A> iterable) {
  if (length < 0) throw RangeError("'length' must be greater than 0");
  return dispatchAsync(iterable, (source) {
    final iterator = source.iterator;
    Iterator<A>? head;
    return SerialAsyncIterator((concurrent) async {
      if (head == null) {
        final arr = <A>[];
        while (true) {
          final r = await iterator.next(concurrent);
          if (r.done) break;
          arr.add(r.value);
        }
        head = dropRight(length, arr).iterator;
      }
      if (head!.moveNext()) return IterResult.value(head!.current);
      return IterResult<A>.done();
    });
  });
}

/// Skips values while [f] returns true, then yields the rest.
///
/// Port of FxTS `dropWhile`.
Iterable<A> dropWhile<A>(bool Function(A a) f, Iterable<A> iterable) sync* {
  final iterator = iterable.iterator;
  while (iterator.moveNext()) {
    if (f(iterator.current)) continue;
    yield iterator.current;
    while (iterator.moveNext()) {
      yield iterator.current;
    }
    return;
  }
}

/// Async counterpart of [dropWhile].
FxAsyncIterable<A> dropWhileAsync<A>(
    FutureOr<bool> Function(A a) f, FxAsyncIterable<A> iterable) {
  return dispatchAsync(iterable, (source) {
    final iterator = source.iterator;
    var dropping = true;
    return SerialAsyncIterator((concurrent) async {
      while (true) {
        final result = await iterator.next(concurrent);
        if (result.done) return IterResult<A>.done();
        if (dropping) {
          if (await f(result.value)) continue;
          dropping = false;
        }
        return result;
      }
    });
  });
}

/// Skips values until [f] returns true — the matching element is dropped
/// too — then yields the rest.
///
/// Port of FxTS `dropUntil`.
Iterable<A> dropUntil<A>(bool Function(A a) f, Iterable<A> iterable) sync* {
  final iterator = iterable.iterator;
  while (iterator.moveNext()) {
    if (f(iterator.current)) break;
  }
  while (iterator.moveNext()) {
    yield iterator.current;
  }
}

/// Async counterpart of [dropUntil].
FxAsyncIterable<A> dropUntilAsync<A>(
    FutureOr<bool> Function(A a) f, FxAsyncIterable<A> iterable) {
  return dispatchAsync(iterable, (source) {
    final iterator = source.iterator;
    var dropping = true;
    return SerialAsyncIterator((concurrent) async {
      while (dropping) {
        final result = await iterator.next(concurrent);
        if (result.done) return IterResult<A>.done();
        if (await f(result.value)) dropping = false;
      }
      return iterator.next(concurrent);
    });
  });
}

/// Returns an iterable of the values between [start] (inclusive) and [end]
/// (exclusive) by index.
///
/// Port of FxTS `slice`. Omit [end] to take everything from [start].
Iterable<A> slice<A>(int start, Iterable<A> iterable, [int? end]) sync* {
  var i = 0;
  for (final item in iterable) {
    if (i >= start && (end == null || i < end)) {
      yield item;
    }
    i += 1;
  }
}

/// Async counterpart of [slice].
FxAsyncIterable<A> sliceAsync<A>(int start, FxAsyncIterable<A> iterable,
    [int? end]) {
  return dispatchAsync(iterable, (source) {
    final iterator = source.iterator;
    var i = 0;
    return SerialAsyncIterator((concurrent) async {
      while (true) {
        final result = await iterator.next(concurrent);
        if (result.done) return IterResult<A>.done();
        final index = i++;
        if (index >= start && (end == null || index < end)) {
          return result;
        }
      }
    });
  });
}

/// Returns an iterable of lists, each containing [size] consecutive
/// elements (the last chunk may be shorter).
///
/// Port of FxTS `chunk`.
Iterable<List<A>> chunk<A>(int size, Iterable<A> iterable) sync* {
  if (size < 1) return;
  var items = <A>[];
  for (final a in iterable) {
    items.add(a);
    if (items.length == size) {
      yield items;
      items = <A>[];
    }
  }
  if (items.isNotEmpty) yield items;
}

/// Async counterpart of [chunk].
FxAsyncIterable<List<A>> chunkAsync<A>(int size, FxAsyncIterable<A> iterable) {
  if (size < 1) return asyncEmpty();
  return dispatchAsync(iterable, (source) {
    final iterator = source.iterator;
    var sourceDone = false;
    return SerialAsyncIterator((concurrent) async {
      if (sourceDone) return IterResult<List<A>>.done();
      final items = <A>[];
      while (items.length < size) {
        final result = await iterator.next(concurrent);
        if (result.done) {
          sourceDone = true;
          break;
        }
        items.add(result.value);
      }
      if (items.isEmpty) return IterResult<List<A>>.done();
      return IterResult.value(items);
    });
  });
}

/// Splits an iterable of single-character strings on the separator [sep].
///
/// Port of FxTS `split`, which iterates strings character-wise; in Dart pass
/// e.g. `'a,b,c'.split('')`.
Iterable<String> split(String sep, Iterable<String> iterable) sync* {
  if (sep == '') {
    yield* iterable;
    return;
  }
  var acc = '';
  var chr = '';
  for (chr in iterable) {
    if (chr == sep) {
      yield acc;
      acc = '';
    } else {
      acc += chr;
    }
  }
  if (chr == sep) {
    yield '';
  } else if (acc.isNotEmpty) {
    yield acc;
  }
}

/// Async counterpart of [split].
FxAsyncIterable<String> splitAsync(
    String sep, FxAsyncIterable<String> iterable) {
  return dispatchAsync(iterable, (source) {
    final iterator = source.iterator;
    var acc = '';
    var chr = '';
    var sourceDone = false;
    return SerialAsyncIterator((concurrent) async {
      // Reaching the source's end always emits the tail (if any) in the same
      // call, so every later call is simply done.
      if (sourceDone) return const IterResult<String>.done();
      while (true) {
        final result = await iterator.next(concurrent);
        if (result.done) {
          sourceDone = true;
          if (sep != '' && chr == sep) return const IterResult.value('');
          if (sep != '' && acc.isNotEmpty) return IterResult.value(acc);
          return const IterResult<String>.done();
        }
        if (sep == '') return IterResult.value(result.value);
        chr = result.value;
        if (chr == sep) {
          final out = acc;
          acc = '';
          return IterResult.value(out);
        }
        acc += chr;
      }
    });
  });
}

/// Yields the elements of [iterable] whose matching element in [selectors]
/// is true.
///
/// Port of FxTS `compress`.
Iterable<B> compress<B>(List<bool> selectors, Iterable<B> iterable) =>
    map((r) => r.$2, filter((r) => r.$1, zip(selectors, iterable)));

/// Async counterpart of [compress].
FxAsyncIterable<B> compressAsync<B>(
        List<bool> selectors, FxAsyncIterable<B> iterable) =>
    mapAsync((r) => r.$2,
        filterAsync((r) => r.$1, zipAsync(toAsync(selectors), iterable)));

// ---- lib/src/lazy/zip.dart ----


/// Merges two iterables into a lazy iterable of record pairs, ending when
/// either input ends.
///
/// Port of FxTS `zip` (TS tuples become Dart records).
///
/// ```dart
/// zip(['a', 'b'], [1, 2]); // (('a', 1), ('b', 2))
/// ```
Iterable<(A, B)> zip<A, B>(Iterable<A> iterable1, Iterable<B> iterable2) sync* {
  final it1 = iterable1.iterator;
  final it2 = iterable2.iterator;
  while (it1.moveNext() && it2.moveNext()) {
    yield (it1.current, it2.current);
  }
}

/// Three-iterable variant of [zip]. (Dart has no variadic generics, so each
/// arity is a separate function.)
Iterable<(A, B, C)> zip3<A, B, C>(
    Iterable<A> iterable1, Iterable<B> iterable2, Iterable<C> iterable3) sync* {
  final it1 = iterable1.iterator;
  final it2 = iterable2.iterator;
  final it3 = iterable3.iterator;
  while (it1.moveNext() && it2.moveNext() && it3.moveNext()) {
    yield (it1.current, it2.current, it3.current);
  }
}

/// Async counterpart of [zip]: pulls both sources in parallel per pair.
FxAsyncIterable<(A, B)> zipAsync<A, B>(
    FxAsyncIterable<A> iterable1, FxAsyncIterable<B> iterable2) {
  return DelegateAsyncIterable(() {
    final it1 = iterable1.iterator;
    final it2 = iterable2.iterator;
    // Pass-through: sub-iterator pulls are issued synchronously before any
    // await, so overlapping next() calls keep pairing by call order while
    // `concurrent` propagates into both sources.
    return DelegateAsyncIterator((concurrent) async {
      final f1 = it1.next(concurrent);
      final f2 = it2.next(concurrent);
      final r1 = await f1;
      final r2 = await f2;
      if (r1.done || r2.done) return IterResult<(A, B)>.done();
      return IterResult.value((r1.value, r2.value));
    });
  });
}

/// Async counterpart of [zip3].
FxAsyncIterable<(A, B, C)> zip3Async<A, B, C>(FxAsyncIterable<A> iterable1,
    FxAsyncIterable<B> iterable2, FxAsyncIterable<C> iterable3) {
  return DelegateAsyncIterable(() {
    final it1 = iterable1.iterator;
    final it2 = iterable2.iterator;
    final it3 = iterable3.iterator;
    return DelegateAsyncIterator((concurrent) async {
      final f1 = it1.next(concurrent);
      final f2 = it2.next(concurrent);
      final f3 = it3.next(concurrent);
      final r1 = await f1;
      final r2 = await f2;
      final r3 = await f3;
      if (r1.done || r2.done || r3.done) {
        return IterResult<(A, B, C)>.done();
      }
      return IterResult.value((r1.value, r2.value, r3.value));
    });
  });
}

/// Zips two iterables through the combining function [f].
///
/// Port of FxTS `zipWith`.
Iterable<C> zipWith<A, B, C>(
        C Function(A a, B b) f, Iterable<A> iterable1, Iterable<B> iterable2) =>
    map((r) => f(r.$1, r.$2), zip(iterable1, iterable2));

/// Async counterpart of [zipWith].
FxAsyncIterable<C> zipWithAsync<A, B, C>(FutureOr<C> Function(A a, B b) f,
        FxAsyncIterable<A> iterable1, FxAsyncIterable<B> iterable2) =>
    mapAsync((r) => f(r.$1, r.$2), zipAsync(iterable1, iterable2));

/// Pairs each element with its index: `(index, value)`.
///
/// Port of FxTS `zipWithIndex`.
Iterable<(int, A)> zipWithIndex<A>(Iterable<A> iterable) sync* {
  var i = 0;
  for (final a in iterable) {
    yield (i++, a);
  }
}

/// Async counterpart of [zipWithIndex].
FxAsyncIterable<(int, A)> zipWithIndexAsync<A>(FxAsyncIterable<A> iterable) {
  return dispatchAsync(iterable, (source) {
    var i = 0;
    return mapAsync((A a) => (i++, a), source).iterator;
  });
}

/// Returns the transposition of the given rows: the n-th output list holds
/// the n-th element of every input row that has one.
///
/// Port of FxTS `transpose` (single-arity: pass the rows as one iterable).
Iterable<List<A>> transpose<A>(Iterable<Iterable<A>> rows) sync* {
  final iterators = rows.map((r) => r.iterator).toList(growable: false);
  if (iterators.isEmpty) return;
  while (true) {
    final current = <A>[];
    for (final it in iterators) {
      if (it.moveNext()) current.add(it.current);
    }
    if (current.isEmpty) return;
    yield current;
  }
}

/// Async counterpart of [transpose].
FxAsyncIterable<List<A>> transposeAsync<A>(Iterable<FxAsyncIterable<A>> rows) {
  return DelegateAsyncIterable(() {
    final iterators = rows.map((r) => r.iterator).toList(growable: false);
    return DelegateAsyncIterator((concurrent) async {
      if (iterators.isEmpty) return IterResult<List<A>>.done();
      final results =
          await Future.wait(iterators.map((it) => it.next(concurrent)));
      final current = [
        for (final r in results)
          if (!r.done) r.value
      ];
      if (current.isEmpty) return IterResult<List<A>>.done();
      return IterResult.value(current);
    });
  });
}

// ---- lib/src/lazy/combine.dart ----


/// Returns an iterable of numbers from [start] (inclusive) to [end]
/// (exclusive), stepping by [step]. With one argument, counts `0..start`.
///
/// Port of FxTS `range`.
///
/// ```dart
/// range(4);        // (0, 1, 2, 3)
/// range(1, 4);     // (1, 2, 3)
/// range(4, 1, -1); // (4, 3, 2)
/// ```
Iterable<int> range(int start, [int? end, int step = 1]) sync* {
  if (end == null) {
    yield* range(0, start);
    return;
  }
  if (step < 0) {
    for (var i = start; i > end; i += step) {
      yield i;
    }
  } else {
    for (var i = start; i < end; i += step) {
      yield i;
    }
  }
}

/// Yields [value] [n] times.
///
/// Port of FxTS `repeat`.
Iterable<T> repeat<T>(int n, T value) sync* {
  for (var i = 0; i < n; i++) {
    yield value;
  }
}

/// Yields the source, then repeats its values indefinitely.
///
/// Port of FxTS `cycle`.
Iterable<T> cycle<T>(Iterable<T> iterable) sync* {
  final arr = <T>[];
  for (final a in iterable) {
    yield a;
    arr.add(a);
  }
  while (arr.isNotEmpty) {
    yield* arr;
  }
}

/// Async counterpart of [cycle].
FxAsyncIterable<T> cycleAsync<T>(FxAsyncIterable<T> iterable) {
  return dispatchAsync(iterable, (source) {
    final iterator = source.iterator;
    final arr = <T>[];
    var sourceDone = false;
    var i = 0;
    return SerialAsyncIterator((concurrent) async {
      if (!sourceDone) {
        final result = await iterator.next(concurrent);
        if (!result.done) {
          arr.add(result.value);
          return result;
        }
        sourceDone = true;
      }
      if (arr.isEmpty) return IterResult<T>.done();
      final value = arr[i % arr.length];
      i++;
      return IterResult.value(value);
    });
  });
}

/// Yields all values of [iterable], then [a].
///
/// Port of FxTS `append`.
Iterable<A> append<A>(A a, Iterable<A> iterable) sync* {
  yield* iterable;
  yield a;
}

/// Async counterpart of [append]. [a] may be a [Future].
FxAsyncIterable<A> appendAsync<A>(FutureOr<A> a, FxAsyncIterable<A> iterable) {
  return dispatchAsync(iterable, (source) {
    final iterator = source.iterator;
    var finished = false;
    return SerialAsyncIterator((concurrent) async {
      if (finished) return IterResult<A>.done();
      final result = await iterator.next(concurrent);
      if (result.done) {
        finished = true;
        return IterResult.value(await a);
      }
      return result;
    });
  });
}

/// Yields [a], then all values of [iterable].
///
/// Port of FxTS `prepend`.
Iterable<A> prepend<A>(A a, Iterable<A> iterable) sync* {
  yield a;
  yield* iterable;
}

/// Async counterpart of [prepend]. [a] may be a [Future].
FxAsyncIterable<A> prependAsync<A>(FutureOr<A> a, FxAsyncIterable<A> iterable) {
  return DelegateAsyncIterable(() {
    final iterator = iterable.iterator;
    var isFirstItem = true;
    return DelegateAsyncIterator((concurrent) async {
      if (isFirstItem) {
        isFirstItem = false;
        return IterResult.value(await a);
      }
      return iterator.next(concurrent);
    });
  });
}

/// Concatenates two iterables lazily.
///
/// Port of FxTS `concat`.
Iterable<A> concat<A>(Iterable<A> iterable1, Iterable<A> iterable2) sync* {
  yield* iterable1;
  yield* iterable2;
}

/// Async counterpart of [concat].
FxAsyncIterable<A> concatAsync<A>(
    FxAsyncIterable<A> iterable1, FxAsyncIterable<A> iterable2) {
  return DelegateAsyncIterable(() {
    final left = iterable1.iterator;
    final right = iterable2.iterator;
    var leftDone = false;
    // Pass-through (not serialized): overlapping pulls must stay parallel so
    // `concurrent` propagates upstream, as in FxTS `concat`.
    return DelegateAsyncIterator((concurrent) async {
      if (!leftDone) {
        final result = await left.next(concurrent);
        if (!result.done) return result;
        leftDone = true;
      }
      return right.next(concurrent);
    });
  });
}

/// Returns the source in reverse order (materializes the source).
///
/// Port of FxTS `reverse`.
Iterable<A> reverse<A>(Iterable<A> iterable) sync* {
  final arr = iterable.toList(growable: false);
  for (var i = arr.length - 1; i >= 0; i--) {
    yield arr[i];
  }
}

/// Async counterpart of [reverse].
FxAsyncIterable<A> reverseAsync<A>(FxAsyncIterable<A> iterable) {
  return dispatchAsync(iterable, (source) {
    final iterator = source.iterator;
    Iterator<A>? reversed;
    return SerialAsyncIterator((concurrent) async {
      if (reversed == null) {
        final arr = <A>[];
        while (true) {
          final r = await iterator.next(concurrent);
          if (r.done) break;
          arr.add(r.value);
        }
        reversed = arr.reversed.iterator;
      }
      if (reversed!.moveNext()) return IterResult.value(reversed!.current);
      return IterResult<A>.done();
    });
  });
}

// --- fork -----------------------------------------------------------------

class _ForkState<T> {
  final Iterator<T> source;
  final buffer = <T>[];
  bool done = false;
  Object? error;
  StackTrace? stackTrace;

  _ForkState(this.source);
}

final Expando<_ForkState<Object?>> _forkStates = Expando('fxdart fork state');

/// Branches a *single* iteration of [iterable] into an independent cursor:
/// every `fork` of the same iterable object shares one underlying iterator
/// and buffer, so the source is walked only once no matter how many forks
/// read from it.
///
/// Port of FxTS `fork`.
Iterable<T> fork<T>(Iterable<T> iterable) sync* {
  var state = _forkStates[iterable] as _ForkState<T>?;
  if (state == null) {
    state = _ForkState<T>(iterable.iterator);
    _forkStates[iterable] = state;
  }
  var i = 0;
  while (true) {
    if (i < state.buffer.length) {
      yield state.buffer[i++];
      continue;
    }
    if (state.error != null) {
      Error.throwWithStackTrace(
          state.error!, state.stackTrace ?? StackTrace.current);
    }
    if (state.done) return;
    final bool moved;
    try {
      moved = state.source.moveNext();
    } catch (e, st) {
      state.error = e;
      state.stackTrace = st;
      rethrow;
    }
    if (!moved) {
      state.done = true;
      return;
    }
    state.buffer.add(state.source.current);
  }
}

class _ForkAsyncState<T> {
  final FxAsyncIterator<T> source;
  final buffer = <T>[];
  bool done = false;
  Object? error;
  StackTrace? stackTrace;
  int pullsInFlight = 0;
  final listeners = <void Function()>[];

  _ForkAsyncState(this.source);

  void _notify() {
    for (final listener in List.of(listeners)) {
      listener();
    }
  }

  /// Issues one parallel pull on the shared source; results land in the
  /// shared buffer in source order (protocol invariant).
  void pull(Concurrent? concurrent) {
    pullsInFlight++;
    source.next(concurrent).then((result) {
      pullsInFlight--;
      if (result.done) {
        done = true;
      } else {
        buffer.add(result.value);
      }
      _notify();
    }, onError: (Object e, StackTrace st) {
      pullsInFlight--;
      error = e;
      stackTrace = st;
      done = true;
      _notify();
    });
  }
}

final Expando<_ForkAsyncState<Object?>> _forkAsyncStates =
    Expando('fxdart async fork state');

/// Async counterpart of [fork]. All forks of the same [FxAsyncIterable]
/// object share one underlying iterator and buffer.
FxAsyncIterable<T> forkAsync<T>(FxAsyncIterable<T> iterable) {
  var state = _forkAsyncStates[iterable] as _ForkAsyncState<T>?;
  if (state == null) {
    state = _ForkAsyncState<T>(iterable.iterator);
    _forkAsyncStates[iterable] = state;
  }
  final s = state;
  return DelegateAsyncIterable(() {
    var i = 0;
    final settlementQueue = <Completer<IterResult<T>>>[];

    void serve() {
      while (settlementQueue.isNotEmpty && i < s.buffer.length) {
        settlementQueue.removeAt(0).complete(IterResult.value(s.buffer[i++]));
      }
      if (s.done && i >= s.buffer.length) {
        while (settlementQueue.isNotEmpty) {
          final completer = settlementQueue.removeAt(0);
          if (s.error != null) {
            completer.completeError(
                s.error!, s.stackTrace ?? StackTrace.current);
          } else {
            completer.complete(IterResult<T>.done());
          }
        }
      }
    }

    // Issues parallel pulls to cover this fork's unmet demand — what lets a
    // downstream `concurrent(n)` evaluate the shared source n-wide. Buffered
    // items still ahead of `i` plus the pulls already in flight each settle
    // one queued completer, so only the shortfall is pulled.
    void pullToMeetDemand(Concurrent? concurrent) {
      while (!s.done &&
          settlementQueue.length > (s.buffer.length - i) + s.pullsInFlight) {
        s.pull(concurrent);
      }
    }

    void Function()? listener;

    return DelegateAsyncIterator((concurrent) {
      if (i < s.buffer.length) {
        return Future.value(IterResult.value(s.buffer[i++]));
      }
      if (s.done && i >= s.buffer.length) {
        if (s.error != null) {
          return Future.error(s.error!, s.stackTrace);
        }
        return Future.value(IterResult<T>.done());
      }
      if (listener == null) {
        listener = () {
          serve();
          // Demand is already covered when the pulls below are issued, so
          // this is a safety net for a shortfall appearing as pulls settle.
          pullToMeetDemand(concurrent);
        };
        s.listeners.add(listener!);
      }
      final completer = Completer<IterResult<T>>();
      settlementQueue.add(completer);
      pullToMeetDemand(concurrent);
      return completer.future;
    });
  });
}

// --- map/object iteration -------------------------------------------------

/// Yields the `(key, value)` pairs of [map] as records.
///
/// Port of FxTS `entries` (TS objects/Maps become Dart Maps).
Iterable<(K, V)> entries<K, V>(Map<K, V> map) sync* {
  for (final e in map.entries) {
    yield (e.key, e.value);
  }
}

/// Yields the keys of [map].
///
/// Port of FxTS `keys`.
Iterable<K> keys<K, V>(Map<K, V> map) => map.keys;

/// Yields the values of [map].
///
/// Port of FxTS `values`.
Iterable<V> values<K, V>(Map<K, V> map) => map.values;

// ---- lib/src/strict/aggregate.dart ----


/// Materializes any iterable into a [List].
///
/// Port of FxTS `toArray` (sync); named `toList` to match Dart's
/// `Iterable.toList` (Dart has no "array" type — this always returns a [List]).
List<A> toList<A>(Iterable<A> iterable) => List.of(iterable);

/// Materializes an [FxAsyncIterable] into a [List].
///
/// Port of FxTS `toArray` (async); named `toListAsync` for Dart idiom.
Future<List<A>> toListAsync<A>(FxAsyncIterable<A> iterable) async {
  final result = <A>[];
  final iterator = iterable.iterator;
  while (true) {
    final r = await iterator.next();
    if (r.done) return result;
    result.add(r.value);
  }
}

/// Iterates over [iterable], applying [f] to each value.
///
/// Port of FxTS `each` (sync).
void each<A>(void Function(A a) f, Iterable<A> iterable) {
  for (final a in iterable) {
    f(a);
  }
}

/// Async counterpart of [each]; awaits [f] per element.
Future<void> eachAsync<A>(
    FutureOr<void> Function(A a) f, FxAsyncIterable<A> iterable) async {
  final iterator = iterable.iterator;
  while (true) {
    final r = await iterator.next();
    if (r.done) return;
    await f(r.value);
  }
}

/// Consumes up to [n] items of [iterable] (all of them when [n] is null),
/// discarding the values — useful to force side effects of a lazy pipeline.
///
/// Port of FxTS `consume`.
void consume<A>(Iterable<A> iterable, [int? n]) {
  final iterator = iterable.iterator;
  var remaining = n;
  while ((remaining == null || remaining-- > 0) && iterator.moveNext()) {}
}

/// Async counterpart of [consume].
Future<void> consumeAsync<A>(FxAsyncIterable<A> iterable, [int? n]) async {
  final iterator = iterable.iterator;
  var remaining = n;
  while (remaining == null || remaining-- > 0) {
    final r = await iterator.next();
    if (r.done) return;
  }
}

/// Folds [iterable] through [f] using its first element as the seed.
/// Throws a [StateError] on an empty iterable.
///
/// Port of FxTS `reduce(f, iterable)`. For the seeded form use [fold].
A reduce<A>(A Function(A acc, A a) f, Iterable<A> iterable) {
  final iterator = iterable.iterator;
  if (!iterator.moveNext()) {
    throw StateError("'reduce' of empty iterable with no initial value");
  }
  var acc = iterator.current;
  while (iterator.moveNext()) {
    acc = f(acc, iterator.current);
  }
  return acc;
}

/// Folds [iterable] through [f], starting from [seed].
///
/// Port of FxTS `reduce(f, seed, iterable)` (named after Dart's
/// `Iterable.fold` since Dart cannot overload by arity).
Acc fold<A, Acc>(Acc seed, Acc Function(Acc acc, A a) f, Iterable<A> iterable) {
  var acc = seed;
  for (final a in iterable) {
    acc = f(acc, a);
  }
  return acc;
}

/// Async counterpart of [reduce].
Future<A> reduceAsync<A>(
    FutureOr<A> Function(A acc, A a) f, FxAsyncIterable<A> iterable) async {
  final iterator = iterable.iterator;
  final first = await iterator.next();
  if (first.done) {
    throw StateError("'reduce' of empty iterable with no initial value");
  }
  var acc = first.value;
  while (true) {
    final r = await iterator.next();
    if (r.done) return acc;
    acc = await f(acc, r.value);
  }
}

/// Async counterpart of [fold].
Future<Acc> foldAsync<A, Acc>(FutureOr<Acc> seed,
    FutureOr<Acc> Function(Acc acc, A a) f, FxAsyncIterable<A> iterable) async {
  var acc = await seed;
  final iterator = iterable.iterator;
  while (true) {
    final r = await iterator.next();
    if (r.done) return acc;
    acc = await f(acc, r.value);
  }
}

/// Returns a reducer section for use in a pipeline: `reduceLazy(f, seed)`
/// gives a function `Iterable<A> -> Acc`.
///
/// Port of FxTS `reduceLazy`.
Acc Function(Iterable<A>) reduceLazy<A, Acc>(
        Acc Function(Acc acc, A a) f, Acc seed) =>
    (iterable) => fold(seed, f, iterable);

/// Adds every number in the iterable.
///
/// Port of FxTS `sum`.
num sum(Iterable<num> iterable) => fold<num, num>(0, (a, b) => a + b, iterable);

/// Sums the key [f] of every element — `map` + [sum] in one step, so a
/// pipeline that only needs a field total doesn't spell out the projection.
///
/// Empty input returns `0` (the [sum] contract).
///
/// Dart-native addition (FxTS has only the numeric `sum`); named after
/// [maxBy]/[minBy] — Kotlin spells it `sumOf`.
num sumBy<A>(num Function(A a) f, Iterable<A> iterable) =>
    fold<A, num>(0, (acc, a) => acc + f(a), iterable);

/// Async counterpart of [sumBy].
Future<num> sumByAsync<A>(
        FutureOr<num> Function(A a) f, FxAsyncIterable<A> iterable) =>
    foldAsync<A, num>(0, (acc, a) async => acc + await f(a), iterable);

/// Async counterpart of [sum].
Future<num> sumAsync(FxAsyncIterable<num> iterable) =>
    foldAsync<num, num>(0, (a, b) => a + b, iterable);

/// Concatenates every string in the iterable.
String sumStrings(Iterable<String> iterable) =>
    fold('', (a, b) => a + b, iterable);

/// Returns the average of the numbers. `NaN` for an empty iterable.
///
/// Port of FxTS `average`.
double average(Iterable<num> iterable) {
  var size = 0;
  num total = 0;
  for (final a in iterable) {
    size++;
    total += a;
  }
  return size == 0 ? double.nan : total / size;
}

/// Async counterpart of [average].
Future<double> averageAsync(FxAsyncIterable<num> iterable) async {
  var size = 0;
  num total = 0;
  await eachAsync((num a) {
    size++;
    total += a;
  }, iterable);
  return size == 0 ? double.nan : total / size;
}

/// Averages the key [f] of every element — `map` + [average] in one step.
///
/// Empty input returns `double.nan` (the [average] contract).
///
/// Dart-native addition completing the by-key family
/// ([sumBy] / [maxBy] / [minBy]).
double averageBy<A>(num Function(A a) f, Iterable<A> iterable) {
  var total = 0.0;
  var count = 0;
  for (final a in iterable) {
    total += f(a);
    count++;
  }
  return count == 0 ? double.nan : total / count;
}

/// Async counterpart of [averageBy].
Future<double> averageByAsync<A>(
    FutureOr<num> Function(A a) f, FxAsyncIterable<A> iterable) async {
  var total = 0.0;
  var count = 0;
  await eachAsync((A a) async {
    total += await f(a);
    count++;
  }, iterable);
  return count == 0 ? double.nan : total / count;
}

num _minOf(num acc, num a) => a.isNaN || acc.isNaN
    ? double.nan
    : a < acc
        ? a
        : acc;

num _maxOf(num acc, num a) => a.isNaN || acc.isNaN
    ? double.nan
    : a > acc
        ? a
        : acc;

/// Returns the smallest number; `infinity` for an empty iterable, `NaN` if
/// any element is `NaN` — mirroring FxTS `min`.
num min(Iterable<num> iterable) => fold(double.infinity, _minOf, iterable);

/// Async counterpart of [min].
Future<num> minAsync(FxAsyncIterable<num> iterable) =>
    foldAsync(double.infinity, _minOf, iterable);

/// Returns the largest number; `-infinity` for an empty iterable, `NaN` if
/// any element is `NaN` — mirroring FxTS `max`.
num max(Iterable<num> iterable) => fold(-double.infinity, _maxOf, iterable);

/// Async counterpart of [max].
Future<num> maxAsync(FxAsyncIterable<num> iterable) =>
    foldAsync(-double.infinity, _maxOf, iterable);

/// Returns the element whose key [f] is smallest, or `null` when empty.
///
/// Keys are compared like [sortBy] compares them ([Comparable.compare]);
/// on ties the **first** encountered element wins. One O(n) walk — no sort.
///
/// Dart-native addition (FxTS has only numeric `min`); named after Kotlin's
/// `minByOrNull` shape, nullable like [head]/[last].
A? minBy<A>(Object? Function(A a) f, Iterable<A> iterable) {
  A? best;
  var seen = false;
  for (final a in iterable) {
    if (!seen || _compareBy(f, a, best as A) < 0) {
      best = a;
      seen = true;
    }
  }
  return best;
}

/// Async counterpart of [minBy].
Future<A?> minByAsync<A>(
    Object? Function(A a) f, FxAsyncIterable<A> iterable) async {
  A? best;
  var seen = false;
  await eachAsync((A a) {
    if (!seen || _compareBy(f, a, best as A) < 0) {
      best = a;
      seen = true;
    }
  }, iterable);
  return best;
}

/// Returns the element whose key [f] is largest, or `null` when empty.
///
/// Keys are compared like [sortBy] compares them ([Comparable.compare]);
/// on ties the **first** encountered element wins. One O(n) walk — no sort.
///
/// Dart-native addition (FxTS has only numeric `max`); named after Kotlin's
/// `maxByOrNull` shape, nullable like [head]/[last].
A? maxBy<A>(Object? Function(A a) f, Iterable<A> iterable) {
  A? best;
  var seen = false;
  for (final a in iterable) {
    if (!seen || _compareBy(f, a, best as A) > 0) {
      best = a;
      seen = true;
    }
  }
  return best;
}

/// Async counterpart of [maxBy].
Future<A?> maxByAsync<A>(
    Object? Function(A a) f, FxAsyncIterable<A> iterable) async {
  A? best;
  var seen = false;
  await eachAsync((A a) {
    if (!seen || _compareBy(f, a, best as A) > 0) {
      best = a;
      seen = true;
    }
  }, iterable);
  return best;
}

/// Returns the number of elements.
///
/// Port of FxTS `size`.
int size<A>(Iterable<A> iterable) {
  var n = 0;
  for (final _ in iterable) {
    n++;
  }
  return n;
}

/// Async counterpart of [size].
Future<int> sizeAsync<A>(FxAsyncIterable<A> iterable) async {
  var n = 0;
  await eachAsync((_) => n++, iterable);
  return n;
}

/// Returns all elements joined into a string, separated by [sep].
///
/// Port of FxTS `join`.
String join<A>(String sep, Iterable<A> iterable) => iterable.join(sep);

/// Async counterpart of [join].
Future<String> joinAsync<A>(String sep, FxAsyncIterable<A> iterable) async =>
    (await toListAsync(iterable)).join(sep);

/// Splits values into groups keyed by [f].
///
/// Port of FxTS `groupBy` (TS objects become Dart Maps).
Map<K, List<A>> groupBy<A, K>(K Function(A a) f, Iterable<A> iterable) {
  final result = <K, List<A>>{};
  for (final a in iterable) {
    result.putIfAbsent(f(a), () => []).add(a);
  }
  return result;
}

/// Async counterpart of [groupBy].
Future<Map<K, List<A>>> groupByAsync<A, K>(
    FutureOr<K> Function(A a) f, FxAsyncIterable<A> iterable) async {
  final result = <K, List<A>>{};
  await eachAsync(
      (A a) async => result.putIfAbsent(await f(a), () => []).add(a), iterable);
  return result;
}

/// Indexes values by [f]; later duplicates overwrite earlier ones.
///
/// Port of FxTS `indexBy`.
Map<K, A> indexBy<A, K>(K Function(A a) f, Iterable<A> iterable) {
  final result = <K, A>{};
  for (final a in iterable) {
    result[f(a)] = a;
  }
  return result;
}

/// Async counterpart of [indexBy].
Future<Map<K, A>> indexByAsync<A, K>(
    FutureOr<K> Function(A a) f, FxAsyncIterable<A> iterable) async {
  final result = <K, A>{};
  await eachAsync((A a) async => result[await f(a)] = a, iterable);
  return result;
}

/// Counts occurrences of each key produced by [f].
///
/// Port of FxTS `countBy`.
Map<K, int> countBy<A, K>(K Function(A a) f, Iterable<A> iterable) {
  final result = <K, int>{};
  for (final a in iterable) {
    result.update(f(a), (n) => n + 1, ifAbsent: () => 1);
  }
  return result;
}

/// Async counterpart of [countBy].
Future<Map<K, int>> countByAsync<A, K>(
    FutureOr<K> Function(A a) f, FxAsyncIterable<A> iterable) async {
  final result = <K, int>{};
  await eachAsync(
      (A a) async => result.update(await f(a), (n) => n + 1, ifAbsent: () => 1),
      iterable);
  return result;
}

/// Returns a **new** sorted list ordered by the comparator [f].
///
/// Port of FxTS `sort`. Unlike the TS version (which mutates arrays in
/// place), the Dart port never mutates its input.
List<A> sort<A>(int Function(A a, A b) f, Iterable<A> iterable) =>
    List.of(iterable)..sort(f);

/// Async counterpart of [sort].
Future<List<A>> sortAsync<A>(
        int Function(A a, A b) f, FxAsyncIterable<A> iterable) async =>
    (await toListAsync(iterable))..sort(f);

/// Alias of [sort]; FxTS added `toSorted` as the non-mutating variant, which
/// the Dart [sort] already is.
List<A> toSorted<A>(int Function(A a, A b) f, Iterable<A> iterable) =>
    sort(f, iterable);

int _compareBy<A>(Object? Function(A a) f, A a, A b) {
  final fa = f(a);
  final fb = f(b);
  if (fa is Comparable && fb is Comparable) {
    return Comparable.compare(
        fa as Comparable<Object?>, fb as Comparable<Object?>);
  }
  return 0;
}

/// Returns a new list sorted by the key extractor [f] (ascending).
///
/// Port of FxTS `sortBy`.
List<A> sortBy<A>(Object? Function(A a) f, Iterable<A> iterable) =>
    sort((a, b) => _compareBy(f, a, b), iterable);

/// Async counterpart of [sortBy].
Future<List<A>> sortByAsync<A>(
        Object? Function(A a) f, FxAsyncIterable<A> iterable) =>
    sortAsync((a, b) => _compareBy(f, a, b), iterable);

/// Splits values into `(pass, fail)` lists by predicate [f].
///
/// Port of FxTS `partition` (TS tuple becomes a Dart record).
(List<A>, List<A>) partition<A>(bool Function(A a) f, Iterable<A> iterable) {
  final pass = <A>[];
  final fail = <A>[];
  for (final a in iterable) {
    (f(a) ? pass : fail).add(a);
  }
  return (pass, fail);
}

/// Async counterpart of [partition].
Future<(List<A>, List<A>)> partitionAsync<A>(
    FutureOr<bool> Function(A a) f, FxAsyncIterable<A> iterable) async {
  final pass = <A>[];
  final fail = <A>[];
  await eachAsync((A a) async => (await f(a) ? pass : fail).add(a), iterable);
  return (pass, fail);
}

// ---- lib/src/strict/access.dart ----


/// Returns the first element, or `null` when empty.
///
/// Port of FxTS `head` (TS `undefined` becomes Dart `null`).
A? head<A>(Iterable<A> iterable) {
  final iterator = iterable.iterator;
  return iterator.moveNext() ? iterator.current : null;
}

/// Async counterpart of [head].
Future<A?> headAsync<A>(FxAsyncIterable<A> iterable) async {
  final r = await iterable.iterator.next();
  return r.done ? null : r.value;
}

/// Returns the last element, or `null` when empty.
///
/// Port of FxTS `last`.
A? last<A>(Iterable<A> iterable) {
  A? result;
  for (final a in iterable) {
    result = a;
  }
  return result;
}

/// Async counterpart of [last].
Future<A?> lastAsync<A>(FxAsyncIterable<A> iterable) async {
  final iterator = iterable.iterator;
  A? result;
  while (true) {
    final r = await iterator.next();
    if (r.done) return result;
    result = r.value;
  }
}

/// Returns the element at [index], or `null` when out of range.
///
/// Port of FxTS `nth`.
A? nth<A>(int index, Iterable<A> iterable) {
  if (index < 0) return null;
  var i = 0;
  for (final a in iterable) {
    if (i++ == index) return a;
  }
  return null;
}

/// Async counterpart of [nth].
Future<A?> nthAsync<A>(int index, FxAsyncIterable<A> iterable) async {
  if (index < 0) return null;
  final iterator = iterable.iterator;
  var i = 0;
  while (true) {
    final r = await iterator.next();
    if (r.done) return null;
    if (i++ == index) return r.value;
  }
}

/// Returns the first element [f] returns true for, or `null`.
///
/// Port of FxTS `find`.
A? find<A>(bool Function(A a) f, Iterable<A> iterable) =>
    head(filter(f, iterable));

/// Async counterpart of [find].
Future<A?> findAsync<A>(
        FutureOr<bool> Function(A a) f, FxAsyncIterable<A> iterable) =>
    headAsync(filterAsync(f, iterable));

/// Returns the index of the first element [f] returns true for, or `-1`.
///
/// Port of FxTS `findIndex`.
int findIndex<A>(bool Function(A a) f, Iterable<A> iterable) {
  for (final (i, a) in zipWithIndex(iterable)) {
    if (f(a)) return i;
  }
  return -1;
}

/// Async counterpart of [findIndex].
Future<int> findIndexAsync<A>(
    FutureOr<bool> Function(A a) f, FxAsyncIterable<A> iterable) async {
  final result = await findAsync((r) => f(r.$2), zipWithIndexAsync(iterable));
  return result == null ? -1 : result.$1;
}

/// Returns true when the iterable contains [a] (`==` comparison).
///
/// Port of FxTS `includes`.
bool includes<A>(A a, Iterable<A> iterable) => iterable.contains(a);

/// Async counterpart of [includes].
Future<bool> includesAsync<A>(A a, FxAsyncIterable<A> iterable) =>
    someAsync((A b) => b == a, iterable);

/// Returns true when every element satisfies [f] (true for an empty
/// iterable). Short-circuits.
///
/// Port of FxTS `every`.
bool every<A>(bool Function(A a) f, Iterable<A> iterable) {
  for (final a in iterable) {
    if (!f(a)) return false;
  }
  return true;
}

/// Async counterpart of [every].
Future<bool> everyAsync<A>(
    FutureOr<bool> Function(A a) f, FxAsyncIterable<A> iterable) async {
  final iterator = iterable.iterator;
  while (true) {
    final r = await iterator.next();
    if (r.done) return true;
    if (!await f(r.value)) return false;
  }
}

/// Returns true when at least one element satisfies [f] (false for an empty
/// iterable). Short-circuits.
///
/// Port of FxTS `some`.
bool some<A>(bool Function(A a) f, Iterable<A> iterable) {
  for (final a in iterable) {
    if (f(a)) return true;
  }
  return false;
}

/// Async counterpart of [some].
Future<bool> someAsync<A>(
    FutureOr<bool> Function(A a) f, FxAsyncIterable<A> iterable) async {
  final iterator = iterable.iterator;
  while (true) {
    final r = await iterator.next();
    if (r.done) return false;
    if (await f(r.value)) return true;
  }
}

/// Value-based emptiness check: true for `null`, `''`, and empty
/// [Iterable]/[Map]/[Set]; false for everything else (numbers, booleans,
/// functions, arbitrary objects).
///
/// Port of FxTS `isEmpty`.
bool isEmpty(Object? value) {
  if (value == null) return true;
  if (value is String) return value.isEmpty;
  if (value is Iterable) return value.isEmpty;
  if (value is Map) return value.isEmpty;
  return false;
}

// ---- lib/src/strict/object.dart ----

/// Builds a map from `(key, value)` records.
///
/// Port of FxTS `fromEntries` (TS entry tuples become Dart records).
///
/// ```dart
/// fromEntries([('a', 1), ('b', 2)]); // {a: 1, b: 2}
/// ```
Map<K, V> fromEntries<K, V>(Iterable<(K, V)> entries) =>
    {for (final (k, v) in entries) k: v};

/// Returns a copy of [map] without the given [keysToOmit].
///
/// Port of FxTS `omit`.
Map<K, V> omit<K, V>(Iterable<K> keysToOmit, Map<K, V> map) {
  final set = keysToOmit.toSet();
  return {
    for (final e in map.entries)
      if (!set.contains(e.key)) e.key: e.value
  };
}

/// Returns a copy of [map] with only the given [keysToPick].
///
/// Port of FxTS `pick`.
Map<K, V> pick<K, V>(Iterable<K> keysToPick, Map<K, V> map) {
  final set = keysToPick.toSet();
  return {
    for (final e in map.entries)
      if (set.contains(e.key)) e.key: e.value
  };
}

/// Returns a copy of [map] without entries matching the predicate [f].
///
/// Port of FxTS `omitBy` (entry tuples become records).
Map<K, V> omitBy<K, V>(bool Function((K, V) entry) f, Map<K, V> map) => {
      for (final e in map.entries)
        if (!f((e.key, e.value))) e.key: e.value
    };

/// Returns a copy of [map] with only entries matching the predicate [f].
///
/// Port of FxTS `pickBy`.
Map<K, V> pickBy<K, V>(bool Function((K, V) entry) f, Map<K, V> map) => {
      for (final e in map.entries)
        if (f((e.key, e.value))) e.key: e.value
    };

/// Returns the value of [key] in [map], or `null`.
///
/// Port of FxTS `prop`.
V? prop<K, V>(K key, Map<K, V> map) => map[key];

/// Returns the values of [propKeys] in [map] (missing keys yield `null`).
///
/// Port of FxTS `props`.
List<V?> props<K, V>(Iterable<K> propKeys, Map<K, V> map) =>
    [for (final k in propKeys) map[k]];

/// Returns a copy of [map] with `null` values removed (shallow).
///
/// Port of FxTS `compactObject`.
Map<K, V> compactObject<K, V>(Map<K, V?> map) => {
      for (final e in map.entries)
        if (e.value != null) e.key: e.value as V
    };

/// Creates a new map by running each value whose key appears in
/// [transformations] through its transformation function.
///
/// Port of FxTS `evolve`. Untransformed keys are kept as-is.
Map<K, Object?> evolve<K>(
    Map<K, Object? Function(Object? value)> transformations,
    Map<K, Object?> map) {
  return {
    for (final e in map.entries)
      e.key: transformations.containsKey(e.key)
          ? transformations[e.key]!(e.value)
          : e.value
  };
}

/// Awaits every value of the map — the async analogue of `Future.wait` for
/// maps.
///
/// Port of FxTS `resolveProps`.
///
/// ```dart
/// await resolveProps({'a': Future.value(1), 'b': 2}); // {a: 1, b: 2}
/// ```
Future<Map<K, V>> resolveProps<K, V>(Map<K, FutureOr<V>> map) async {
  final result = <K, V>{};
  for (final e in map.entries) {
    result[e.key] = await e.value;
  }
  return result;
}

/// Deep partial match: checks whether [target] contains everything in
/// [pattern]. Maps match when every pattern entry matches recursively;
/// iterables match pairwise; anything else compares with `==`.
///
/// Port of FxTS `isMatch`.
bool isMatch(Object? target, Object? pattern) {
  if (pattern is Map) {
    if (target is! Map) return false;
    for (final e in pattern.entries) {
      if (!target.containsKey(e.key) || !isMatch(target[e.key], e.value)) {
        return false;
      }
    }
    return true;
  }
  if (pattern is Iterable) {
    if (target is! Iterable) return false;
    final ti = target.iterator;
    final pi = pattern.iterator;
    while (pi.moveNext()) {
      if (!ti.moveNext() || !isMatch(ti.current, pi.current)) return false;
    }
    // FxTS matches when the pattern is a prefix of the target.
    return true;
  }
  return target == pattern;
}

/// Curried [isMatch]: returns a predicate that matches against [pattern].
///
/// Port of FxTS `matches`.
bool Function(Object? target) matches(Object? pattern) =>
    (target) => isMatch(target, pattern);

