/// Adds two values. Works for any type supporting `+` ([num], [String],
/// [List], ...) — mirrors FxTS `add`, which accepts numbers and strings.
T add<T extends Object>(T a, T b) => (a as dynamic) + b as T;

/// Returns a function that always returns [a], ignoring an optional
/// argument (so it can be used as a unary callback).
///
/// Port of FxTS `always`.
T Function([Object? _]) always<T>(T a) => ([Object? _]) => a;

/// Calls [f] with [args] as positional arguments.
///
/// Port of FxTS `apply`.
R apply<R>(Function f, List<Object?> args) => Function.apply(f, args) as R;

/// Returns its argument unchanged.
///
/// Port of FxTS `identity`.
T identity<T>(T a) => a;

/// Does nothing.
///
/// Port of FxTS `noop`.
void noop() {}

/// Boolean negation.
///
/// Port of FxTS `not` (Dart has no truthiness, so this takes a [bool]).
bool not(bool a) => !a;

/// Returns a predicate that negates [f].
///
/// Port of FxTS `negate`.
bool Function(T) negate<T>(bool Function(T) f) => (a) => !f(a);

/// Calls [f] with [a] for its side effect, then returns [a].
///
/// Port of FxTS `tap` (data-first; close over [f] for the curried style).
T tap<T>(void Function(T a) f, T a) {
  f(a);
  return a;
}

/// Returns `callback(value)` when the predicate holds, otherwise [value].
///
/// Port of FxTS `when`. TS can widen the return union `T | R`; in Dart both
/// branches must share the type [T].
T when<T>(bool Function(T) predicate, T Function(T) callback, T value) =>
    predicate(value) ? callback(value) : value;

/// The opposite of [when]: applies [callback] when the predicate fails.
///
/// Port of FxTS `unless`.
T unless<T>(bool Function(T) predicate, T Function(T) callback, T value) =>
    predicate(value) ? value : callback(value);

/// Returns a unary function that throws `toError(value)`.
///
/// Port of FxTS `throwError`.
Never Function(T) throwError<T>(Object Function(T) toError) =>
    (a) => throw toError(a);

/// Throws `toError(value)` when the predicate holds; otherwise returns
/// [value] unchanged.
///
/// Port of FxTS `throwIf`.
T throwIf<T>(bool Function(T) predicate, Object Function(T) toError, T value) {
  if (predicate(value)) throw toError(value);
  return value;
}

int _compare(Object? a, Object? b) {
  if (a is Comparable && b is Comparable) {
    if (a.runtimeType != b.runtimeType &&
        !(a is num && b is num) &&
        !(a is String && b is String)) {
      throw ArgumentError(
          'The values you want to compare must be of the same type');
    }
    return Comparable.compare(
        a as Comparable<Object?>, b as Comparable<Object?>);
  }
  throw ArgumentError('The values must be Comparable');
}

/// `a > b`. Port of FxTS `gt` (data-first; use a closure for currying:
/// `(b) => gt(5, b)`).
bool gt(Object? a, Object? b) => _compare(a, b) > 0;

/// `a >= b`. Port of FxTS `gte`.
bool gte(Object? a, Object? b) => _compare(a, b) >= 0;

/// `a < b`. Port of FxTS `lt`.
bool lt(Object? a, Object? b) => _compare(a, b) < 0;

/// `a <= b`. Port of FxTS `lte`.
bool lte(Object? a, Object? b) => _compare(a, b) <= 0;

/// Applies every function in [fns] to [a] and collects the results.
///
/// Port of FxTS `juxt` (unary form — Dart has no variadic generics).
///
/// ```dart
/// juxt([min, max])([3, 4, 9, 1]); // [1, 9]
/// ```
List<R> Function(T a) juxt<T, R>(List<R Function(T a)> fns) =>
    (a) => [for (final f in fns) f(a)];

/// Memoizes a unary function by its argument (`==`/`hashCode` keyed).
///
/// Port of FxTS `memoize` (unary only; TS's variadic/`WeakMap` behavior has
/// no Dart equivalent).
R Function(A) memoize<A, R>(R Function(A) f) {
  final cache = <A, R>{};
  return (a) => cache.putIfAbsent(a, () => f(a));
}

/// Returns a [Future] that completes with [value] after [wait].
///
/// Port of FxTS `delay`.
///
/// ```dart
/// await delay(Duration(seconds: 1), 'a'); // 'a' after 1s
/// ```
Future<T> delay<T>(Duration wait, T value) => Future.delayed(wait, () => value);

/// Returns a [Future] that completes after [wait].
Future<void> sleep(Duration wait) => Future.delayed(wait);

/// Builds a matcher from `predicate, mapper` pairs with an optional
/// default. When nothing matches and no [orElse] is given, the value itself
/// is returned (it must then be an `R`).
///
/// Port of FxTS `cases`; Dart cannot type variadic pairs, so they are passed
/// as records.
///
/// ```dart
/// final classify = cases<int, String>([
///   ((n) => n < 0, (n) => 'negative'),
///   ((n) => n == 0, (n) => 'zero'),
/// ], orElse: (n) => 'positive');
/// classify(-4); // 'negative'
/// ```
R Function(T value) cases<T, R>(List<(bool Function(T), R Function(T))> pairs,
    {R Function(T)? orElse}) {
  return (value) {
    for (final (predicate, mapper) in pairs) {
      if (predicate(value)) return mapper(value);
    }
    if (orElse != null) return orElse(value);
    if (value is R) return value;
    throw StateError('cases: no case matched and no orElse given');
  };
}

/// Splits a string into a list of user-perceived characters, handling
/// surrogate pairs — the same behavior as FxTS `unicodeToArray`, which
/// splits by code point. Named `unicodeToList` for Dart idiom (returns a List).
List<String> unicodeToList(String s) =>
    [for (final rune in s.runes) String.fromCharCode(rune)];

/// FxTS-named alias of [unicodeToList].
List<String> unicodeToArray(String s) => unicodeToList(s);

/// TypeScript's `curry` relies on reflection over a function's arity plus
/// recursive conditional types (`Curry<...>`), neither of which exists in
/// Dart. This stub only curries binary functions and is untyped. The typed,
/// Dart-native replacement is the `.curried` extension getter (arities 2–5)
/// — see `WHY_CURRIED.md`.
@Deprecated('Use the .curried extension getter instead (see WHY_CURRIED.md)')
Function curry(Function f) => (Object? a) => (Object? b) => f(a, b);

// ---- lib/src/strict/curried.dart ----
/// Dart-idiomatic currying: the `.curried` / `.uncurried` extension getters.
///
/// FxTS's `curry` cannot be ported as a function — it relies on runtime arity
/// reflection and recursive conditional types, neither of which exists in
/// Dart. Instead, one extension per arity is declared under the same getter
/// name, and the compiler picks the right one from the function's *static*
/// type. Full design rationale: `WHY_CURRIED.md` at the repository root.
///
/// ```dart
/// int add(int a, int b) => a + b;
/// final addOne = add.curried(1); // int Function(int)
/// addOne(2); // 3
/// ```

/// Curries a binary function: `f.curried(a)(b) == f(a, b)`.
///
/// Dart-native replacement for FxTS `curry` (see `WHY_CURRIED.md`).
extension Curry2<A, B, R> on R Function(A, B) {
  /// The curried form: `f.curried(a)(b) == f(a, b)`.
  R Function(B) Function(A) get curried => (a) => (b) => this(a, b);
}

/// Curries a ternary function: `f.curried(a)(b)(c) == f(a, b, c)`.
extension Curry3<A, B, C, R> on R Function(A, B, C) {
  /// The curried form: `f.curried(a)(b)(c) == f(a, b, c)`.
  R Function(C) Function(B) Function(A) get curried =>
      (a) => (b) => (c) => this(a, b, c);
}

/// Curries a 4-ary function.
extension Curry4<A, B, C, D, R> on R Function(A, B, C, D) {
  /// The curried form: `f.curried(a)(b)(c)(d) == f(a, b, c, d)`.
  R Function(D) Function(C) Function(B) Function(A) get curried =>
      (a) => (b) => (c) => (d) => this(a, b, c, d);
}

/// Curries a 5-ary function.
extension Curry5<A, B, C, D, E, R> on R Function(A, B, C, D, E) {
  /// The curried form: `f.curried(a)(b)(c)(d)(e) == f(a, b, c, d, e)`.
  R Function(E) Function(D) Function(C) Function(B) Function(A) get curried =>
      (a) => (b) => (c) => (d) => (e) => this(a, b, c, d, e);
}

/// Uncurries a 2-level function chain: `f.uncurried(a, b) == f(a)(b)`.
///
/// When the chain is nested deeper, the *deepest* matching arity wins; apply
/// an extension explicitly (`Uncurry2(f).uncurried`) to flatten fewer levels.
extension Uncurry2<A, B, R> on R Function(B) Function(A) {
  /// The flattened form: `f.uncurried(a, b) == f(a)(b)`.
  R Function(A, B) get uncurried => (a, b) => this(a)(b);
}

/// Uncurries a 3-level function chain.
extension Uncurry3<A, B, C, R> on R Function(C) Function(B) Function(A) {
  /// The flattened form: `f.uncurried(a, b, c) == f(a)(b)(c)`.
  R Function(A, B, C) get uncurried => (a, b, c) => this(a)(b)(c);
}

/// Uncurries a 4-level function chain.
extension Uncurry4<A, B, C, D, R>
    on R Function(D) Function(C) Function(B) Function(A) {
  /// The flattened form: `f.uncurried(a, b, c, d) == f(a)(b)(c)(d)`.
  R Function(A, B, C, D) get uncurried => (a, b, c, d) => this(a)(b)(c)(d);
}

/// Uncurries a 5-level function chain.
extension Uncurry5<A, B, C, D, E, R>
    on R Function(E) Function(D) Function(C) Function(B) Function(A) {
  /// The flattened form: `f.uncurried(a, b, c, d, e) == f(a)(b)(c)(d)(e)`.
  R Function(A, B, C, D, E) get uncurried =>
      (a, b, c, d, e) => this(a)(b)(c)(d)(e);
}

// ---- lib/src/strict/predicates.dart ----
/// Type/value predicates ported from FxTS. Several of them exist only for
/// API parity — in Dart, prefer `is` checks and pattern matching. They stay
/// useful as tear-offs for `filter`, `takeWhile`, etc.

/// True when [a] is `null`.
///
/// Port of FxTS `isNull`.
bool isNull(Object? a) => a == null;

/// True when [a] is not `null`.
bool isNotNull(Object? a) => a != null;

/// Port of FxTS `isNil` (`null` or `undefined`). Dart has no `undefined`,
/// so this is exactly [isNull].
bool isNil(Object? a) => a == null;

/// TODO(port): TypeScript distinguishes `undefined` from `null`; Dart has
/// only `null`, so this cannot be ported meaningfully.
@Deprecated('Dart has no undefined; use isNull instead')
bool isUndefined(Object? a) => a == null;

/// True when [a] is a [bool]. Port of FxTS `isBoolean` (Dart type: `bool`).
bool isBool(Object? a) => a is bool;

/// FxTS-named alias of [isBool].
bool isBoolean(Object? a) => isBool(a);

/// True when [a] is a [num]. Port of FxTS `isNumber` (Dart type: `num`).
bool isNum(Object? a) => a is num;

/// FxTS-named alias of [isNum].
bool isNumber(Object? a) => isNum(a);

/// True when [a] is a [String]. Port of FxTS `isString`.
bool isString(Object? a) => a is String;

/// True when [a] is a [DateTime]. Port of FxTS `isDate` (Dart type: `DateTime`).
bool isDateTime(Object? a) => a is DateTime;

/// FxTS-named alias of [isDateTime].
bool isDate(Object? a) => isDateTime(a);

/// True when [a] is a [List]. Port of FxTS `isArray`.
bool isList(Object? a) => a is List;

/// TODO(port): JS `Array` maps to Dart [List]; kept as a deprecated alias.
@Deprecated('Use isList instead')
bool isArray(Object? a) => a is List;

/// True when [a] is a [Map]. The closest analogue of FxTS `isObject`
/// (`typeof a === "object"`), whose plain-JS-object semantics do not exist
/// in Dart.
bool isMap(Object? a) => a is Map;

/// TODO(port): JS plain objects map to Dart [Map]s; kept as a deprecated
/// alias of [isMap].
@Deprecated('Use isMap instead')
bool isObject(Object? a) => a is Map;

